8	import Foundation
9	
10	@Observable
11	final class AlarmLevelSetupViewModel {
12	    
13	    private final class LastState {
14	        var last1: Decimal
15	        var last2: Decimal
16	        
17	        init(last1: Decimal, last2: Decimal) {
18	            self.last1 = last1
19	            self.last2 = last2
20	        }
21	    }
22	    
23	    private let alarmLevel: Alarm.Level
24	    
25	    var displayedValueLevel1: AlarmWheelModel
26	    var displayedValueLevel2: AlarmWheelModel
27	            
28	    init(alarmLevel: Alarm.Level) {
29	        self.alarmLevel = alarmLevel
30	        let radiationType = alarmLevel.radiationType
31	       
32	        func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
33	            let rawMax = alarmLevel.offScale ?? radiationType.defaultMaxValue
34	
35	            func step(for value: Decimal) -> Decimal {
36	                var step = minStep
37	                var threshold = switchAt
38	
39	                while value >= threshold * 10 {
40	                    step *= 10
41	                    threshold *= 10
42	                }
43	
44	                return step
45	            }
46	
47	            let topStep = step(for: rawMax)
48	            var ceiled = Decimal()
49	            var divided = rawMax / topStep
50	            NSDecimalRound(&ceiled, &divided, 0, .up)
51	            let maxValue = ceiled * topStep
52	            
53	            var values: [Decimal] = []
54	            var value = maxValue
55	
56	            while value > 0 {
57	                values.append(value)
58	                let currentStep = step(for: value)
59	                let next = value - currentStep
60	                let nextStep = next > 0 ? step(for: next) : minStep
61	
62	                if nextStep < currentStep {
63	                    value = value - nextStep
64	                } else {
65	                    value = next <= 0 ? 0 : next
66	                }
67	            }
68	            values.append(0)
69	
70	            return values
71	        }
72	        
73	        let values: [Decimal] = {
74	            switch radiationType {
75	            case .radiationLevel(let level):
76	                switch level {
77	                case .countRate:
78	                    makeValues(minStep: 0.1, switchAt: 20)
79	
80	                case .doseRate:
81	                    makeValues(minStep: 0.01, switchAt: 2)
82	                }
83	
84	            case .dose:
85	                makeValues(minStep: 1, switchAt: 100)
86	            }
87	        }()
88	        
89	        self.displayedValueLevel1 = .init(initialValue: alarmLevel.level1 ?? 0, radiationType: radiationType, values: values)
90	        self.displayedValueLevel2 = .init(initialValue: alarmLevel.level2 ?? 0, radiationType: radiationType, values: values)
91	
92	        let state = LastState(last1: displayedValueLevel1.selectedValue, last2: displayedValueLevel2.selectedValue)
93	
94	        withObservationTracking { [weak self] in
95	            guard let self else { return }
96	            let level1 = self.displayedValueLevel1.selectedValue
97	            let level2 = self.displayedValueLevel2.selectedValue
98	            
99	            let level1Changed = (level1 != state.last1)
100	            let level2Changed = (level2 != state.last2)
101	
102	            defer {
103	                state.last1 = level1
104	                state.last2 = level2
105	            }
106	            
107	            if level2Changed && !level1Changed {
108	                // двигают level2 -> level1 следует за ним
109	                if level2 < level1 {
110	                    self.displayedValueLevel1.selectedValue = level2
111	                }
112	            } else if level1Changed && !level2Changed {
113	                // двигают level1 -> level2 следует за ним
114	                if level1 > level2 {
115	                    self.displayedValueLevel2.selectedValue = level1
116	                }
117	            }
118	        }
119	    }
120	    
121	    func alarmsChanged() -> Bool {
122	        alarmLevel.level1 != displayedValueLevel1.selectedValue || alarmLevel.level2 != displayedValueLevel2.selectedValue
123	    }
124	}
125	
126	private extension RadiationType {
127	    var defaultMaxValue: Decimal {
128	        switch self {
129	        case .radiationLevel(let level):
130	            switch level {
131	            case .countRate:
132	                50000
133	            case .doseRate:
134	                1000
135	            }
136	        case .dose:
137	            10000000
138	        }
139	    }
140	}
